// Generate registry entries
export function generateToolRegistry(): ToolRegistryEntry[] {
  return MIRAI_TOOLS.map((toolName, index) => ({
    id: `mirai-tool-${index}`,
    name: toolName,
    component: `Tool${toolName.replace(/[^a-zA-Z0-9]/g, '')}Component`,
    tab: AppTab.DYNAMIC_TOOL,
    icon: index % 3 === 0 ? 'fa-microchip' : (index % 3 === 1 ? 'fa-bolt' : 'fa-shield-halved'),
    category: 'MIRAI_BOTNET'
  }));
}

export const TOOL_REGISTRY = generateToolRegistry();
